import{_ as o,o as c,c as a,a0 as t}from"./chunks/framework.BH9V8Et6.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),d={name:"changelog.md"};function r(i,e,n,l,s,h){return c(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>This page mirrors the canonical <a href="https://github.com/1broseidon/ketch/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a> in the repo root. Versions follow <a href="https://semver.org/" target="_blank" rel="noreferrer">Semantic Versioning</a> and match the published git tags.</p><h2 id="v0-12-0-—-2026-07-15" tabindex="-1">v0.12.0 — 2026-07-15 <a class="header-anchor" href="#v0-12-0-—-2026-07-15" aria-label="Permalink to &quot;v0.12.0 — 2026-07-15&quot;">​</a></h2><p><strong>Added</strong></p><ul><li><strong>BYO-cookie support</strong> (#25): ketch loads a Netscape <code>cookies.txt</code> jar — the format exported by browser cookies.txt extensions and consumed by <code>curl</code>/<code>yt-dlp</code> — and injects matching cookies on both the HTTP and headless-browser fetch paths, unblocking session- and consent-gated pages. <code>--cookie-file &lt;path&gt;</code> on <code>scrape</code>, <code>search</code> (for <code>--scrape</code> fetches), and <code>crawl</code>, plus a persistent <code>cookie_file</code> config key (the flag overrides config; an explicit empty flag disables cookies for the run). Scope (Domain, HostOnly, Path, Secure) is re-matched on every request and redirect; a configured jar gets an isolated page-cache namespace; cookie values are never printed anywhere, and a group/world-readable jar triggers a <code>chmod 600</code> warning.</li><li><strong>Multiple API keys per provider</strong> (#23): plural config fields (<code>brave_api_keys</code>, <code>exa_api_keys</code>, <code>firecrawl_api_keys</code>, <code>keenable_api_keys</code>) alongside the singular keys. A random key is picked per request to spread rate limits, with one retry on 401/429 (402 for Firecrawl) when the pool holds more than one. <code>config set</code> accepts JSON arrays, <code>ketch config</code> reports <code>*_api_keys_count</code> only, and <code>ketch doctor</code> probes the effective pools.</li><li><strong>Random provider selection</strong> (#24): <code>ketch search --random</code> (or <code>--random=brave,exa</code>) shuffles the candidate backends, tries one, and falls back to the rest on failure — stopping at the first successful response. Mirrors <code>--multi</code> flag semantics, mutually exclusive with <code>--backend</code>/<code>--multi</code>, with MCP parity via the <code>search</code> tool&#39;s <code>random</code> input.</li><li><strong>PDF text extraction</strong> for <code>scrape</code>, <code>search --scrape</code>, and <code>crawl</code> (#19): text-based PDFs are detected by MIME type or <code>%PDF-</code> magic bytes and extracted with a built-in pure-Go parser. An optional external converter (<code>external_pdf_to_md_converter_command</code> with exactly one <code>{input}</code> placeholder, plus <code>external_pdf_to_md_converter_timeout_sec</code>, default 300) is authoritative when configured. <code>--raw</code> and <code>--select</code> reject PDFs (exit 2); PDFs without a text layer are precondition errors (exit 5) with an OCR hint.</li><li>Bundled skill verb renamed <code>research.md</code> → <code>ketch-research.md</code> (#22) to avoid namespace conflicts.</li></ul><h2 id="v0-11-0-—-2026-07-07" tabindex="-1">v0.11.0 — 2026-07-07 <a class="header-anchor" href="#v0-11-0-—-2026-07-07" aria-label="Permalink to &quot;v0.11.0 — 2026-07-07&quot;">​</a></h2><p><strong>Added</strong></p><ul><li><strong>Federated multi-backend search</strong>: <code>ketch search --multi</code> (and the MCP <code>search</code> tool&#39;s <code>multi</code> input) queries several backends at once and fuses their rankings with <a href="https://doi.org/10.1145/1571941.1572114" target="_blank" rel="noreferrer">Reciprocal Rank Fusion</a>, so a page multiple engines rank highly rises to the top. Bare <code>--multi</code> federates every usable backend (zero-config installs still get ddg + exa + keenable); <code>--multi=brave,exa</code> picks an explicit set (the <code>=</code> is required for a list). Results are deduplicated by URL canonicalization, each backend gets a 10s timeout with graceful degradation (<code>failed:</code> frontmatter / additive MCP <code>errors</code> map), and every fused result lists the engines that found it.</li><li><code>firecrawl</code> web search backend via the <a href="https://docs.firecrawl.dev" target="_blank" rel="noreferrer">Firecrawl</a> v2 search API, configured with <code>ketch config set firecrawl_api_key &lt;key&gt;</code> and selected with <code>-b firecrawl</code>. Reports <code>firecrawl_api_key_set</code> in <code>ketch config</code> discovery and is covered by a live <code>ketch doctor</code> probe.</li><li><code>keenable</code> web search backend over the Keenable index, built for AI agents. Keyless by default (public endpoint, rate-limited); an optional <code>keenable_api_key</code> lifts the rate limit.</li><li><code>ketch extract</code> — pipe HTML through ketch&#39;s readability + markdown pipeline with no fetch: <code>curl -L &lt;url&gt; | ketch extract</code>. Supports <code>--url</code> (metadata + relative-link resolution), <code>--select</code>, <code>--trim</code>, <code>--max-chars</code>, and the global <code>--json</code>; deliberately no cache, browser, or MCP surface.</li><li>Claude Code plugin + marketplace manifest: <code>claude plugin marketplace add 1broseidon/ketch</code>, then <code>claude plugin install ketch@ketch</code> wires up <code>ketch mcp serve</code> and the bundled agent skill. Optional convenience — the stateless CLI remains the zero-infrastructure path.</li></ul><h2 id="v0-10-0-—-2026-07-01" tabindex="-1">v0.10.0 — 2026-07-01 <a class="header-anchor" href="#v0-10-0-—-2026-07-01" aria-label="Permalink to &quot;v0.10.0 — 2026-07-01&quot;">​</a></h2><p><strong>Added</strong></p><ul><li><code>ketch mcp serve</code> — ketch as an MCP server over stdio, exposing <code>search</code>, <code>code</code>, <code>docs</code>, <code>scrape</code>, and <code>crawl</code> with the same config-driven backends as the CLI, stable <code>[kind]</code> error prefixes mirroring the CLI exit codes, and concise server instructions in the initialize result.</li><li>Bundled agent skill at <code>skills/ketch/</code> — a SKILL.md playbook any skill-loading agent can install: surface routing, token budgets, error-prefix control flow, a deep-research recipe, and a guided backend-setup flow.</li><li><code>ketch doctor</code> — deterministic live health checks for every surface (search/code/docs backends, browser, cache) with <code>ok</code> / <code>no_key</code> / <code>unreachable</code> / <code>misconfigured</code> statuses, fix hints (including the SearXNG <code>format: json</code> trap), aligned human output or stable <code>--json</code>.</li><li>Key-presence booleans in <code>ketch config</code> discovery (<code>brave_api_key_set</code>, <code>exa_api_key_set</code>, <code>context7_api_key_set</code>, <code>github_token_set</code>) so agents can tell &quot;unconfigured&quot; from &quot;ready&quot; in one call.</li><li>Shared config-driven constructors (<code>search/code/docs/scrape/cache.NewFromConfig</code>) used by both the CLI and MCP server, ending backend-switch drift. MIT LICENSE file.</li></ul><p><strong>Changed</strong></p><ul><li><code>ketch docs --library</code> on a non-context7 backend and <code>ketch code --regex</code> on GitHub are clear validation errors instead of silent re-routes; the unimplemented <code>local</code> docs backend is rejected up front and no longer advertised.</li></ul><p><strong>Fixed</strong></p><ul><li>Context7 404s classify as not-found (exit 3) instead of retryable-upstream; <code>docs --resolve</code> respects <code>--limit</code>; <code>ketch cache --json</code> emits stable JSON; unknown-backend errors list the valid options; a data race in the scraper&#39;s browser-binary resolution.</li></ul><h2 id="v0-9-5-—-2026-06-29" tabindex="-1">v0.9.5 — 2026-06-29 <a class="header-anchor" href="#v0-9-5-—-2026-06-29" aria-label="Permalink to &quot;v0.9.5 — 2026-06-29&quot;">​</a></h2><p><strong>Fixed</strong></p><ul><li>Tables render as GFM pipe tables across readability, raw, and selector extraction paths (#14).</li><li>Brave searches cap the API <code>count</code> at Brave&#39;s per-request maximum of 20, preventing HTTP 422 when <code>--limit</code> is higher (#17).</li><li>Client-rendered SPA pages (e.g. Next.js App Router) are no longer misdetected as static; adds a <code>spa_markers</code> config key to extend detection (#15).</li></ul><h2 id="v0-9-4-—-2026-06-22" tabindex="-1">v0.9.4 — 2026-06-22 <a class="header-anchor" href="#v0-9-4-—-2026-06-22" aria-label="Permalink to &quot;v0.9.4 — 2026-06-22&quot;">​</a></h2><p><strong>Added</strong></p><ul><li><code>exa</code> web search backend via Exa&#39;s hosted MCP endpoint, with optional <code>exa_api_key</code> config for authenticated usage.</li><li><code>ketch scrape --force-browser</code> — always render via the configured browser, skipping JS-shell auto-detection (#12); composes with <code>--raw</code> and <code>--select</code>. Documents the previously-undocumented <code>--raw</code> flag (#11).</li></ul><h2 id="v0-9-3-—-2026-05-29" tabindex="-1">v0.9.3 — 2026-05-29 <a class="header-anchor" href="#v0-9-3-—-2026-05-29" aria-label="Permalink to &quot;v0.9.3 — 2026-05-29&quot;">​</a></h2><p><strong>Added</strong></p><ul><li><code>grepapp</code> code search backend (Grep MCP, <code>mcp.grep.app</code>) — keyless, literal/regex search across 1M+ public GitHub repos. Now the default for <code>ketch code</code> (was <code>sourcegraph</code>).</li><li><code>ketch code --regex</code> interprets the query as a regular expression. Supported on <code>grepapp</code> and <code>sourcegraph</code>; <code>github</code> rejects it because REST code search is literal-only.</li></ul><p><strong>Changed</strong></p><ul><li><code>code.Searcher</code> interface refactored from positional params to a <code>Query</code> struct so backend options can grow without signature churn.</li></ul><p><strong>Fixed</strong></p><ul><li>Documentation drift across README, CLAUDE.md, and the site reference: corrected the <code>ketch code</code> default backend, scoped <code>-b/--backend</code> to <code>search</code>/<code>code</code>/<code>docs</code>, documented previously-missing flags and the <code>version</code> command, and synced the <code>ketch config</code> discovery JSON example with real output.</li></ul><h2 id="v0-9-2-—-2026-05-24" tabindex="-1">v0.9.2 — 2026-05-24 <a class="header-anchor" href="#v0-9-2-—-2026-05-24" aria-label="Permalink to &quot;v0.9.2 — 2026-05-24&quot;">​</a></h2><p><strong>Added</strong></p><ul><li>Differentiated exit codes so scripts and agents can distinguish failure classes: <code>2</code> validation/bad input, <code>3</code> not found, <code>4</code> upstream/network, <code>5</code> precondition (missing API key/token), <code>6</code> interrupted.</li></ul><p><strong>Changed</strong></p><ul><li><code>ketch crawl</code> no longer swallows Ctrl+C as exit 0. SIGINT during a foreground crawl exits <code>6</code> while still printing the summary collected before shutdown.</li><li><code>-b/--backend</code> is no longer a persistent root flag — it lives on <code>search</code> (matching the existing <code>code</code> and <code>docs</code> local flags). <code>ketch -b ddg search &quot;q&quot;</code> and <code>ketch search -b ddg &quot;q&quot;</code> both still work.</li></ul><h2 id="v0-9-1-—-2026-05-22" tabindex="-1">v0.9.1 — 2026-05-22 <a class="header-anchor" href="#v0-9-1-—-2026-05-22" aria-label="Permalink to &quot;v0.9.1 — 2026-05-22&quot;">​</a></h2><p><strong>Added</strong></p><ul><li><code>url_rewrites</code> config: an ordered list of <code>{match, replace}</code> regex rules applied transparently before any fetch in <code>scrape</code>, <code>search --scrape</code>, and <code>crawl</code>. Redirect URLs without touching the agent surface (e.g. <code>www.reddit.com</code> → <code>old.reddit.com</code>). The original URL is preserved in output as <code>url:</code>; the fetched URL appears as <code>fetched_url:</code> when different.</li></ul><p><strong>Changed</strong></p><ul><li><code>crawl.Crawl()</code> now takes a <code>*scrape.Scraper</code> from the caller (<code>Options.BrowserBin</code> removed). Affects only direct importers of the <code>crawl</code> package — the CLI is unchanged.</li></ul><p><strong>Fixed</strong></p><ul><li>Broken example URLs in the README (#8, thanks @abhmul).</li></ul><h2 id="v0-9-0-—-2026-05-12" tabindex="-1">v0.9.0 — 2026-05-12 <a class="header-anchor" href="#v0-9-0-—-2026-05-12" aria-label="Permalink to &quot;v0.9.0 — 2026-05-12&quot;">​</a></h2><p><strong>Changed</strong></p><ul><li><strong>Breaking.</strong> Reusable packages moved from <code>pkg/&lt;pkg&gt;</code> to the module root. Import paths change from <code>github.com/1broseidon/ketch/pkg/&lt;pkg&gt;</code> to <code>github.com/1broseidon/ketch/&lt;pkg&gt;</code>.</li><li>VitePress documentation site moved from <code>docs/</code> to <code>site/</code>, freeing <code>docs/</code> for the docs-search Go package. Site URL is unaffected.</li></ul><h2 id="v0-8-1-—-2026-05-12" tabindex="-1">v0.8.1 — 2026-05-12 <a class="header-anchor" href="#v0-8-1-—-2026-05-12" aria-label="Permalink to &quot;v0.8.1 — 2026-05-12&quot;">​</a></h2><p><strong>Fixed</strong></p><ul><li>Page cache no longer returns unrendered JS-shell content after a browser is configured. Entries record their fetch source (<code>http</code> / <code>http_shell</code> / <code>browser</code>); JS-shell hits are bypassed once a browser is available, and pre-existing entries migrate in place. Fixes #7.</li></ul><h2 id="v0-8-0-—-2026-05-02" tabindex="-1">v0.8.0 — 2026-05-02 <a class="header-anchor" href="#v0-8-0-—-2026-05-02" aria-label="Permalink to &quot;v0.8.0 — 2026-05-02&quot;">​</a></h2><p><strong>Changed</strong></p><ul><li>Reusable packages moved from <code>internal/</code> to <code>pkg/</code> (<code>cache</code>, <code>code</code>, <code>config</code>, <code>crawl</code>, <code>docs</code>, <code>extract</code>, <code>httpx</code>, <code>scrape</code>, <code>search</code>, <code>updatecheck</code>). Pure rename — exposes them for import by external Go programs.</li></ul><h2 id="v0-7-1-—-2026-04-21" tabindex="-1">v0.7.1 — 2026-04-21 <a class="header-anchor" href="#v0-7-1-—-2026-04-21" aria-label="Permalink to &quot;v0.7.1 — 2026-04-21&quot;">​</a></h2><p><strong>Fixed</strong></p><ul><li><code>ketch docs --resolve &lt;name&gt;</code> returned HTTP 400 after an upstream Context7 API change. Query param renamed (<code>?q=</code> → <code>?query=</code>), results moved into a <code>{&quot;results&quot;: [...]}</code> envelope, and field names updated. <code>ketch docs &lt;query&gt;</code> and <code>--library</code> were unaffected.</li></ul><h2 id="v0-7-0-—-2026-04-21" tabindex="-1">v0.7.0 — 2026-04-21 <a class="header-anchor" href="#v0-7-0-—-2026-04-21" aria-label="Permalink to &quot;v0.7.0 — 2026-04-21&quot;">​</a></h2><p><strong>Added</strong></p><ul><li><code>ketch version</code> command and <code>--version</code> flag — reports build version, commit, and date.</li><li>Passive update reminder when a newer release exists (cached 24h, throttled). Honors <code>KETCH_NO_UPDATE_NOTIFIER=1</code>, <code>CI</code>, <code>--json</code>, and non-TTY stderr.</li><li>Ctrl+C (SIGINT) and SIGTERM cancel the root context, so foreground <code>ketch crawl</code> drains gracefully.</li></ul><p><strong>Changed</strong></p><ul><li>HTTP stack tuned for crawling: a shared <code>*http.Transport</code> with a 30s timeout, <code>MaxIdleConnsPerHost=16</code>, HTTP/2, and a keep-alive dialer, reused by every backend.</li><li><code>context.Context</code> plumbed through the scraper, browser, crawler, and sitemap/llms.txt fetches — cancellation reaches into Rod and <code>http.Client.Do</code>.</li><li>All HTTP response bodies capped at 20 MiB via <code>io.LimitReader</code>.</li></ul><h2 id="v0-6-0-—-2026-04-11" tabindex="-1">v0.6.0 — 2026-04-11 <a class="header-anchor" href="#v0-6-0-—-2026-04-11" aria-label="Permalink to &quot;v0.6.0 — 2026-04-11&quot;">​</a></h2><p><strong>Added</strong></p><ul><li><code>ketch scrape</code> smart input detection: multiple args, JSON array, file (one URL per line), or stdin pipe — auto-detected, no extra flags.</li><li><code>--concurrency N</code> on <code>ketch scrape</code> (default 5) — semaphore-based worker pool.</li><li><code>--select</code> and <code>--no-llms-txt</code> now propagate to multi-URL scraping.</li></ul><p><strong>Changed</strong></p><ul><li><code>search.Searcher.Search</code> and <code>docs.Searcher.Search</code> now take <code>context.Context</code> as the first param, consistent with <code>code.Searcher</code>.</li></ul><h2 id="v0-5-0-—-2026-04-11" tabindex="-1">v0.5.0 — 2026-04-11 <a class="header-anchor" href="#v0-5-0-—-2026-04-11" aria-label="Permalink to &quot;v0.5.0 — 2026-04-11&quot;">​</a></h2><p><strong>Added</strong></p><ul><li><code>ketch scrape --select &lt;css&gt;</code> — CSS selector extraction, bypasses readability (with browser fallback for JS-rendered pages).</li><li><code>ketch scrape --max-chars N</code> — truncate markdown output to N Unicode code points.</li><li><code>ketch scrape --trim</code> — strip markdown formatting while preserving content text (typically 30–40% token reduction).</li><li><code>ketch search/code/docs --minimal</code> — one result per line, tab-separated, pipe-friendly.</li><li>llms.txt auto-detection: bare domain URLs check <code>/llms.txt</code> and return it directly when found. Disable with <code>--no-llms-txt</code>.</li></ul><h2 id="v0-4-0-—-2026-04-11" tabindex="-1">v0.4.0 — 2026-04-11 <a class="header-anchor" href="#v0-4-0-—-2026-04-11" aria-label="Permalink to &quot;v0.4.0 — 2026-04-11&quot;">​</a></h2><p><strong>Added</strong></p><ul><li><code>ketch code -b github</code> — GitHub Code Search backend. Token resolution: explicit config → <code>$GITHUB_TOKEN</code> → <code>$GH_TOKEN</code> → <code>gh auth token</code>.</li><li>GitHub backend populates star counts via a single batched GraphQL call.</li><li><code>github_token_source</code> field in the <code>ketch config</code> discovery payload (the token itself is never printed).</li></ul><p><strong>Changed</strong></p><ul><li><code>code.Searcher.Search</code> takes <code>context.Context</code> as its first arg; backends use <code>http.NewRequestWithContext</code> for cancellation.</li></ul><h2 id="v0-3-0-—-2026-04-10" tabindex="-1">v0.3.0 — 2026-04-10 <a class="header-anchor" href="#v0-3-0-—-2026-04-10" aria-label="Permalink to &quot;v0.3.0 — 2026-04-10&quot;">​</a></h2><p><strong>Added</strong></p><ul><li><code>ketch code</code> command — code search via the Sourcegraph streaming SSE API. Zero config.</li><li><code>ketch docs</code> command — library documentation search via Context7. Requires an API key.</li><li>Config keys: <code>code_backend</code>, <code>docs_backend</code>, <code>context7_api_key</code>, <code>sourcegraph_url</code>.</li></ul><h2 id="v0-2-0" tabindex="-1">v0.2.0 <a class="header-anchor" href="#v0-2-0" aria-label="Permalink to &quot;v0.2.0&quot;">​</a></h2><p>Browser rendering, crawl, and cache overhaul.</p><ul><li><strong>Browser rendering</strong>: JS-rendered pages (React, Angular, Salesforce Lightning) automatically detected and re-fetched via headless Chrome using Rod. <ul><li><code>ketch config set browser chrome</code> — configure browser</li><li><code>ketch browser install</code> — download Chromium</li><li><code>ketch browser status</code> — check browser availability</li><li>Transparent fallback — agents see the same output format</li></ul></li><li><strong>Crawl command</strong>: BFS and sitemap-based site crawling. <ul><li><code>ketch crawl &lt;url&gt;</code> — BFS crawl with configurable depth and concurrency</li><li><code>ketch crawl &lt;url&gt; --sitemap</code> — sitemap-based crawl</li><li><code>ketch crawl &lt;url&gt; --background</code> — detached process with status tracking</li><li><code>ketch crawl status</code> / <code>ketch crawl stop</code> — monitor and control background crawls</li></ul></li><li><strong>Cache backend</strong>: migrated from filesystem to an embedded bbolt database. <ul><li>Single <code>cache.db</code> file; <code>Store</code> interface for future backends</li><li>Default TTL changed to 72h; shared cache between scrape and crawl</li></ul></li></ul><h2 id="v0-1-0" tabindex="-1">v0.1.0 <a class="header-anchor" href="#v0-1-0" aria-label="Permalink to &quot;v0.1.0&quot;">​</a></h2><p>Initial release.</p><ul><li>Search via Brave, DuckDuckGo, or SearXNG</li><li>Scrape URLs to clean markdown (readability + html-to-markdown)</li><li>Concurrent batch scraping</li><li>YAML frontmatter + markdown output format</li><li>JSON config at <code>~/.config/ketch/config.json</code></li><li>TTL-based page cache with platform-correct paths</li><li><code>ketch config</code> discovery payload for agent introspection</li><li><code>--json</code> flag on all commands</li><li>GoReleaser + Homebrew tap publishing</li></ul>',79)])])}const g=o(d,[["render",r]]);export{p as __pageData,g as default};
